  var NOAHS_WORLD_DEFAULTS={project:"Noah's Waters",period:'Ancient Biblical / Hebrew era',clothing:'Ancient Hebrew clothing only. No modern clothing or accessories.',diversity:'Diverse ancient town population. African, Indian, Asian, Middle Eastern represented.',forbidden:'No modern objects. No modern buildings. No modern hairstyles. No fantasy or styling.',style:'Cinematic, naturalistic, historically authentic. Rich earth tones.',familyCount:'Ark family-only scenes must use exact approved family count.',crowd:'Crowd scenes may include more than eight people only when marked as crowd scene.',authenticity:'Maintain approved faces, body types, wardrobe, and emotional tone across all scenes.',negative:'Watermark, text overlay, modern clothing, fantasy elements, unrealistic proportions, duplicate faces'};
  function aid_switch_tab(tabId){var panels=document.querySelectorAll('.ls-aid-panel');panels.forEach(function(p){p.style.display='none';});var tabs=document.querySelectorAll('.ls-aid-tab');tabs.forEach(function(t){t.classList.remove('active');});var panel=document.getElementById('aid-tab-'+tabId);if(panel)panel.style.display='block';var tab=document.querySelector('[data-aid-tab="'+tabId+'"]');if(tab)tab.classList.add('active');}
