    var charSaveBtn=document.getElementById('aid-char-save-btn');
    if(charSaveBtn){charSaveBtn.addEventListener('click',function(){var c=read_char_form();if(!c.name){aid_confirm('aid-char-confirm','Character name is required.','#ff8080');return;}var chars=load_chars();var existIdx=chars.findIndex(function(x){return x.name===c.name;});if(existIdx>=0){chars[existIdx]=Object.assign(chars[existIdx],c,{canonical:chars[existIdx].canonical});}else{chars.push(c);}save_chars(chars);render_char_select();render_char_list();aid_confirm('aid-char-confirm','Character saved: '+c.name,'#5ee0a5');});}
