    var scSaveBtn=document.getElementById('aid-sc-save-btn');
    if(scSaveBtn){scSaveBtn.addEventListener('click',function(){var sc={title:gv('aid-sc-title'),type:gv('aid-sc-type'),location:gv('aid-sc-location'),time:gv('aid-sc-time'),weather:gv('aid-sc-weather'),mood:gv('aid-sc-mood'),characters:gv('aid-sc-characters'),wardrobeNotes:gv('aid-sc-wardrobe-notes'),action:gv('aid-sc-action'),camera:gv('aid-sc-camera'),lighting:gv('aid-sc-lighting'),composition:gv('aid-sc-composition'),requiredObjects:gv('aid-sc-required-objects'),forbiddenObjects:gv('aid-sc-forbidden-objects'),continuityNotes:gv('aid-sc-continuity-notes'),savedAt:new Date().toISOString()};if(!sc.title){aid_confirm('aid-sc-confirm','Scene title is required.','#ff8080');return;}var scenes=load_scenes();var existIdx=scenes.findIndex(function(x){return x.title===sc.title;});if(existIdx>=0)scenes[existIdx]=sc;else scenes.push(sc);save_scene_data(scenes);render_scene_list();aid_confirm('aid-sc-confirm','Scene saved: '+sc.title,'#5ee0a5');});}
    var cinematicBtn=document.getElementById('aid-sc-cinematic-btn');
    if(cinematicBtn){cinematicBtn.addEventListener('click',function(){var prompt=gen_cinematic_prompt();sv('aid-po-cinematic',prompt);var log=aid_read(KEYS.prompts)||[];log.push({type:'cinematic',scene:gv('aid-sc-title'),prompt:prompt,savedAt:new Date().toISOString()});aid_write(KEYS.prompts,log);aid_switch_tab('prompt-output');});}
    var correctionBtn=document.getElementById('aid-sc-correction-btn');
    if(correctionBtn){correctionBtn.addEventListener('click',function(){var selected=[];document.querySelectorAll('[data-issue].active').forEach(function(b){selected.push(b.dataset.issue);});if(!selected.length)selected=['Scene needs correction'];var prompt=gen_correction_prompt(selected);sv('aid-po-correction',prompt);var log=aid_read(KEYS.prompts)||[];log.push({type:'correction',scene:gv('aid-sc-title'),issues:selected,prompt:prompt,savedAt:new Date().toISOString()});aid_write(KEYS.prompts,log);aid_switch_tab('prompt-output');});}
    var negativeBtn=document.getElementById('aid-sc-negative-btn');
    if(negativeBtn){negativeBtn.addEventListener('click',function(){var prompt=gen_negative_prompt();sv('aid-po-negative',prompt);aid_switch_tab('prompt-output');});}
    var img2imgBtn=document.getElementById('aid-sc-img2img-btn');
    if(img2imgBtn){img2imgBtn.addEventListener('click',function(){var prompt=gen_img2img_prompt();sv('aid-po-img2img',prompt);aid_switch_tab('prompt-output');});}
    document.addEventListener('click',function(e){var ib=e.target.closest('[data-issue]');if(!ib)return;var p=document.getElementById('lsAIDirectorPanel');if(!p||!p.contains(ib))return;ib.classList.toggle('active');ib.style.background=ib.classList.contains('active')?'rgba(255,128,0,.25)':'';ib.style.borderColor=ib.classList.contains('active')?'rgba(255,128,0,.6)':'';});
    ['cinematic','correction','negative','img2img'].forEach(function(type){var btn=document.getElementById('aid-po-copy-'+type);if(btn){btn.addEventListener('click',function(){var ta=document.getElementById('aid-po-'+type);if(!ta||!ta.value){aid_confirm('aid-po-confirm','No prompt to copy.','#ff8080');return;}if(navigator.clipboard){navigator.clipboard.writeText(ta.value).then(function(){aid_confirm('aid-po-confirm','Copied to clipboard.','#5ee0a5');}).catch(function(){aid_confirm('aid-po-confirm','Copy not available. Long-press to copy.','#ffb300');});}else{ta.select();aid_confirm('aid-po-confirm','Select the text above and copy it.','#ffb300');}});}});
    var statuses=['approved','correction','char-mismatch','scene-mismatch','cropped','random','rejected'];
    var statusLabels={approved:'Approved',correction:'Needs Correction','char-mismatch':'Character Mismatch','scene-mismatch':'Scene Mismatch',cropped:'Cropped/Cut Off',random:'Random/Unrelated',rejected:'Rejected'};
    statuses.forEach(function(s){var btn=document.getElementById('aid-rv-'+s+'-btn');if(btn){btn.addEventListener('click',function(){var checks={};for(var i=1;i<=12;i++){var cb=document.getElementById('aid-rv-check-'+i);checks['check'+i]=cb?cb.checked:false;}var flaggedIssues=[];var rvPanel=document.getElementById('aid-tab-image-review');if(rvPanel){rvPanel.querySelectorAll('[data-issue].active').forEach(function(b){flaggedIssues.push(b.dataset.issue);});}var entry={sceneRef:gv('aid-rv-scene-ref'),notes:gv('aid-rv-notes'),wrongNotes:gv('aid-rv-wrong'),keepNotes:gv('aid-rv-keep'),changeNotes:gv('aid-rv-change'),correctionPrompt:gv('aid-rv-correction-out'),flaggedIssues:flaggedIssues,status:statusLabels[s],checks:checks,savedAt:new Date().toISOString()};if(_currentImageData){entry.imageData=_currentImageData;entry.imageName=_currentImageName;}var reviews=aid_read(KEYS.reviews)||[];reviews.push(entry);try{aid_write(KEYS.reviews,reviews);}catch(e){}var takes=load_takes();takes.push(Object.assign({},entry));try{aid_write(KEYS.takes,takes);}catch(e){takes[takes.length-1].imageData=null;try{aid_write(KEYS.takes,takes);}catch(e2){}}render_takes_list(_currentFilter);aid_switch_tab('approved-takes');aid_confirm('aid-rv-confirm','Saved as: '+statusLabels[s],'#5ee0a5');});}});
    ['all','Approved','Needs Correction','Rejected'].forEach(function(f){var btnId='aid-takes-filter-'+(f==='all'?'all':f==='Approved'?'approved':f==='Needs Correction'?'correction':'rejected');var btn=document.getElementById(btnId);if(btn){btn.addEventListener('click',function(){_currentFilter=f;render_takes_list(f);});}});
