    var clrImg=document.getElementById('aid-rv-clear-img');if(clrImg){clrImg.addEventListener('click',function(){_currentImageData=null;_currentImageName='';_reviewZoom=1;var img=document.getElementById('aid-rv-img');var ph=document.getElementById('aid-rv-placeholder');var lbl=document.getElementById('aid-rv-img-label');var file=document.getElementById('aid-rv-file');if(img){img.src='';img.style.display='none';}if(ph)ph.style.display='';if(lbl)lbl.textContent='Current Image';if(file)file.value='';});}
